const handleSend = (userMessage: string) => {
  if (!userMessage.trim()) return
  activate()
  sendMessage({ role: 'user', content: userMessage })
}

// Map AI SDK messages to the shape MessageList expects
const displayMessages = messages.map((m) => ({
  id: m.id,
  role: m.role as 'user' | 'assistant',
  content: m.parts?.map((p: { type: string; text?: string }) => p.type === 'text' ? p.text ?? '' : '').join('') ?? '',
  timestamp: m.createdAt ?? new Date(),
  isStreaming: isLoading && m.role === 'assistant' && m === messages[messages.length - 1],
}))

