import { createOpenAI } from '@ai-sdk/openai'
import { createGoogleGenerativeAI } from '@ai-sdk/google'
import { streamText } from 'ai'
import { NextRequest } from 'next/server'

export const runtime = 'nodejs'

const SYSTEM_PROMPT = `You are Chyren — a sovereign intelligence orchestrator. \
You operate with precision, no stubs, and no hallucinations. \
You route tasks through verified AI providers with integrity checks. \
Be concise, direct, and authoritative.`

function getModel() {
  const ollamaBase = process.env.OLLAMA_BASE_URL ?? 'http://localhost:11434/v1'
  const isLocalOllama = ollamaBase.includes('localhost') || ollamaBase.includes('127.0.0.1')

  // On Vercel (or any non-local env) fall back to Gemini
  if (isLocalOllama && process.env.VERCEL) {
    const google = createGoogleGenerativeAI({
      apiKey: process.env.GEMINI_API_KEY ?? '',
    })
    return google(process.env.GEMINI_MODEL ?? 'gemini-2.0-flash')
  }

  // Local: use ollama + gemma4
  const ollama = createOpenAI({
    baseURL: ollamaBase,
    apiKey: 'ollama',
  })
  return ollama(process.env.OLLAMA_MODEL ?? 'gemma4:e2b')
}

export async function POST(req: NextRequest) {
  try {
    const { messages = [], message } = await req.json()

    const chatMessages = messages.length
      ? messages
      : [{ role: 'user' as const, content: message ?? '' }]

    if (!chatMessages.length || !chatMessages[chatMessages.length - 1]?.content) {
      return new Response(JSON.stringify({ error: 'Message is required' }), {
        status: 400,
        headers: { 'Content-Type': 'application/json' },
      })
    }

    const result = streamText({
      model: getModel(),
      system: SYSTEM_PROMPT,
      messages: chatMessages,
    })

    return result.toUIMessageStreamResponse()
  } catch (error) {
    console.error('Chat stream error:', error)
    return new Response(JSON.stringify({ error: 'Internal server error' }), {
      status: 500,
      headers: { 'Content-Type': 'application/json' },
    })
  }
}

@tailwind base;
@tailwind components;
@tailwind utilities;

@import url('https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600&family=JetBrains+Mono:wght@300;400;500&display=swap');

* {
  margin: 0;
