::-webkit-scrollbar-thumb { background: rgba(99, 102, 241, 0.3); border-radius: 2px; }
::-webkit-scrollbar-thumb:hover { background: rgba(99, 102, 241, 0.5); }

/* Focus */
input:focus, textarea:focus, button:focus { outline: none; }

/* Omega glow */
.omega-glow {
  text-shadow: 0 0 20px rgba(99, 102, 241, 0.8), 0 0 40px rgba(99, 102, 241, 0.4);
}

/* Status bar */
.status-bar {
  background: rgba(3, 7, 18, 0.9);
  border-bottom: 1px solid rgba(99, 102, 241, 0.15);
}

/* Terminal panel */
.terminal-panel {
  background: rgba(3, 7, 18, 0.95);
  border: 1px solid rgba(99, 102, 241, 0.12);
}

/* Input area */
.input-area {
  background: rgba(15, 23, 42, 0.8);
  border: 1px solid rgba(99, 102, 241, 0.2);
  transition: border-color 0.2s;
}
.input-area:focus-within {
  border-color: rgba(99, 102, 241, 0.5);
  box-shadow: 0 0 0 1px rgba(99, 102, 241, 0.15), 0 0 20px rgba(99, 102, 241, 0.05);
}

/* Message entry */
.msg-user {
  border-left: 2px solid rgba(99, 102, 241, 0.6);
  background: rgba(99, 102, 241, 0.04);
}
.msg-assistant {
  border-left: 2px solid rgba(16, 185, 129, 0.5);
  background: rgba(16, 185, 129, 0.02);
}

/* Cursor blink */
@keyframes blink {
  0%, 100% { opacity: 1; }
  50% { opacity: 0; }
}
.cursor { animation: blink 1s step-end infinite; }

/* Fade up */
@keyframes fadeUp {
  from { opacity: 0; transform: translateY(6px); }
  to   { opacity: 1; transform: translateY(0); }
}
.fade-up { animation: fadeUp 0.25s ease forwards; }

/* Pulse dot */
@keyframes pulseDot {
  0%, 100% { opacity: 1; transform: scale(1); }
  50%       { opacity: 0.4; transform: scale(0.8); }
}
.pulse-dot { animation: pulseDot 1.4s ease-in-out infinite; }
.pulse-dot:nth-child(2) { animation-delay: 0.2s; }
.pulse-dot:nth-child(3) { animation-delay: 0.4s; }

/* Grid bg */
.grid-bg {
  background-image:
    linear-gradient(rgba(99, 102, 241, 0.04) 1px, transparent 1px),
    linear-gradient(90deg, rgba(99, 102, 241, 0.04) 1px, transparent 1px);
  background-size: 40px 40px;
}

/* Vercel-style badge */
.badge {
