.msg-content p { margin-bottom: 6px; line-height: 1.65; }
.msg-content ul, .msg-content ol { margin: 6px 0 6px 20px; }
.msg-content li { margin: 3px 0; line-height: 1.6; }
.msg-content strong { color: #e2e8f0; font-weight: 600; }
.msg-content h1, .msg-content h2, .msg-content h3 {
  color: #c7d2fe;
  font-weight: 600;
  margin: 10px 0 4px;
