            style={{ background: '#10b981' }}
          />
        )}
      </div>
    </div>
  )
}

'use client'

import React, { useEffect, useRef } from 'react'
import { ChatMessage } from './ChatMessage'

export interface Message {
  id: string
  role: 'user' | 'assistant'
  content: string
  timestamp: Date
  isStreaming?: boolean
}

interface MessageListProps {
  messages: Message[]
  isLoading?: boolean
}

export function MessageList({ messages, isLoading = false }: MessageListProps) {
  const endRef = useRef<HTMLDivElement>(null)

  useEffect(() => {
    endRef.current?.scrollIntoView({ behavior: 'smooth' })
  }, [messages])

  if (messages.length === 0) {
    return (
      <div className="flex-1 flex flex-col items-center justify-center gap-6 px-8 grid-bg">
        <div className="text-center">
          <div
            className="font-mono text-7xl font-light mb-4 omega-glow select-none"
            style={{ color: '#6366f1' }}
          >
            Ω
          </div>
          <div className="font-mono text-xs tracking-[0.3em] text-slate-500 uppercase mb-2">
            Sovereign Intelligence Orchestrator
          </div>
          <div className="font-mono text-xs text-slate-700 mb-8">v2.0 // ADCCL ACTIVE</div>
          <div className="grid grid-cols-3 gap-3 max-w-sm mx-auto">
            {['Task Routing', 'ADCCL Verify', 'Ledger Commit'].map((label) => (
              <div
                key={label}
                className="terminal-panel rounded px-3 py-2 text-center"
              >
                <div className="w-1.5 h-1.5 rounded-full bg-emerald-500 mx-auto mb-1.5"
                  style={{ boxShadow: '0 0 6px #10b981' }}
                />
                <div className="font-mono text-xs text-slate-500">{label}</div>
              </div>
            ))}
          </div>
        </div>
        <div className="font-mono text-xs text-slate-700 text-center">
          Type a command or ask a question to begin
        </div>
      </div>
    )
  }

  return (
    <div className="flex-1 overflow-y-auto flex flex-col divide-y divide-slate-800/50">
      {messages.map((msg, i) => (
        <ChatMessage
          key={msg.id}
          role={msg.role}
          content={msg.content}
          timestamp={msg.timestamp}
          isStreaming={msg.isStreaming}
          index={i}
        />
      ))}
      {isLoading && messages[messages.length - 1]?.role !== 'assistant' && (
        <div className="px-5 py-3 msg-assistant fade-up">
          <div className="flex items-center gap-3 mb-2">
            <span className="font-mono text-xs font-medium tracking-wider" style={{ color: '#10b981' }}>
              Ω CHYREN
            </span>
            <span className="badge badge-amber">PROCESSING</span>
          </div>
          <div className="pl-3 flex items-center gap-1.5">
            {[0, 1, 2].map((i) => (
              <span
                key={i}
                className="pulse-dot w-1 h-1 rounded-full"
                style={{ background: '#10b981', animationDelay: `${i * 0.2}s` }}
              />
            ))}
          </div>
        </div>
      )}
      <div ref={endRef} />
    </div>
  )
}

'use client'

import React, { useRef, useState, useCallback, useEffect } from 'react'
import { useVoiceEngine } from '@/hooks/useVoiceEngine'

interface ChatInputProps {
  onSend: (message: string) => void
  disabled?: boolean
  isLoading?: boolean
}

export function ChatInput({ onSend, disabled = false, isLoading = false }: ChatInputProps) {
  const [input, setInput] = useState('')
  const textareaRef = useRef<HTMLTextAreaElement>(null)

  const handleTranscript = useCallback((text: string) => {
    setInput((prev) => (prev ? prev + ' ' + text : text))
  }, [])

  const { isRecording, startRecording, stopRecording } = useVoiceEngine(handleTranscript)

  useEffect(() => {
    if (textareaRef.current) {
      textareaRef.current.style.height = '22px'
      textareaRef.current.style.height = Math.min(textareaRef.current.scrollHeight, 120) + 'px'
    }
  }, [input])

  const handleSend = useCallback(() => {
    if (input.trim() && !disabled && !isLoading) {
      onSend(input.trim())
      setInput('')
      if (textareaRef.current) textareaRef.current.style.height = '22px'
    }
  }, [input, disabled, isLoading, onSend])

  const handleKeyDown = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault()
      handleSend()
    }
  }

  return (
    <div className="input-area rounded-lg px-4 py-3 flex items-end gap-3">
      {/* Prompt glyph */}
      <span
        className="font-mono text-sm flex-shrink-0 pb-0.5 select-none"
        style={{ color: '#6366f1' }}
      >
        ▸
      </span>

      <textarea
        ref={textareaRef}
        value={input}
        onChange={(e) => setInput(e.target.value)}
        onKeyDown={handleKeyDown}
        placeholder="Enter command or query…"
        disabled={disabled || isLoading}
        className="flex-1 bg-transparent font-mono text-sm text-slate-200 placeholder-slate-700 resize-none focus:outline-none disabled:opacity-40 leading-relaxed"
        rows={1}
        style={{ minHeight: '22px' }}
      />

      {/* Voice */}
      <button
        onClick={isRecording ? stopRecording : startRecording}
        disabled={disabled || isLoading}
        className="flex-shrink-0 w-7 h-7 rounded flex items-center justify-center transition-all duration-150 disabled:opacity-30"
        style={{
          background: isRecording ? 'rgba(248,113,113,0.15)' : 'rgba(99,102,241,0.1)',
          border: `1px solid ${isRecording ? 'rgba(248,113,113,0.4)' : 'rgba(99,102,241,0.2)'}`,
          color: isRecording ? '#f87171' : '#818cf8',
        }}
        title={isRecording ? 'Stop recording' : 'Voice input'}
      >
        {isRecording ? (
          <svg className="w-3 h-3" fill="currentColor" viewBox="0 0 20 20">
            <rect x="5" y="5" width="3.5" height="10" rx="1"/>
            <rect x="11.5" y="5" width="3.5" height="10" rx="1"/>
          </svg>
        ) : (
          <svg className="w-3 h-3" fill="currentColor" viewBox="0 0 20 20">
            <path d="M10 2a3 3 0 0 0-3 3v5a3 3 0 0 0 6 0V5a3 3 0 0 0-3-3zM7 14.5A5 5 0 0 0 15 10h-1.5a3.5 3.5 0 0 1-7 0H5a5 5 0 0 0 5 4.5V16H8v1.5h4V16h-2v-1.5z"/>
          </svg>
        )}
      </button>

      {/* Send */}
      <button
        onClick={handleSend}
        disabled={!input.trim() || disabled || isLoading}
        className="flex-shrink-0 w-7 h-7 rounded flex items-center justify-center transition-all duration-150 disabled:opacity-20"
        style={{
          background: 'rgba(99,102,241,0.15)',
          border: '1px solid rgba(99,102,241,0.35)',
          color: '#818cf8',
        }}
        title="Send (Enter)"
      >
        {isLoading ? (
          <svg className="w-3 h-3 animate-spin" fill="none" viewBox="0 0 24 24">
            <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="3"/>
            <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z"/>
          </svg>
        ) : (
          <svg className="w-3 h-3" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" d="M5 12h14M12 5l7 7-7 7"/>
          </svg>
        )}
      </button>
    </div>
  )
}

