1	//! omega-spokes: Standardized provider adapters.
2	//! This crate implements the interface for LLM providers (Anthropic, OpenAI, etc.),
3	//! translating requests into provider-specific formats and normalizing responses.
4	
5	#![warn(missing_docs)]
6	
7	use async_trait::async_trait;
8	use omega_core::{ProviderRequest, ProviderResponse};
9	use reqwest::Client;
10	use serde_json::json;
11	
12	/// Capability supported by a provider (used for integration routing)
13	#[derive(Debug, Clone, PartialEq, Eq)]
14	pub enum SpokeCapability {
15	    /// Supports structured tool calling
16	    ToolCalling,
17	    /// Supports vision input
18	    Vision,
19	}
20	
21	/// Invocation of a tool
22	#[derive(Debug, Clone, serde::Serialize, serde::Deserialize)]
23	pub struct ToolInvocation {
24	    /// Name of the tool
25	    pub name: String,
26	    /// Arguments for the tool
27	    pub arguments: String,
28	}
29	
30	/// Trait for all LLM spokes
31	#[async_trait]
32	pub trait ProviderSpoke: Send + Sync {
33	    /// Send a request to the provider and return a normalized response
34	    async fn send(&self, request: ProviderRequest) -> ProviderResponse;
35	    /// Return the name of the provider
36	    fn name(&self) -> String;
37	    /// Discover capabilities of this spoke
38	    async fn discover_tools(&self) -> Result<Vec<ToolInvocation>, String>;
39	}
40	
41	/// Anthropic Spoke: Implementation for Claude
42	pub struct AnthropicSpoke {
43	    /// API Key
44	    pub api_key: String,
45	    client: Client,
46	}
47	
48	impl AnthropicSpoke {
49	    /// Create new Anthropic spoke
50	    pub fn new(api_key: String) -> Self {
51	        Self {
52	            api_key,
53	            client: Client::new(),
54	        }
55	    }
56	}
57	
58	#[async_trait]
59	impl ProviderSpoke for AnthropicSpoke {
60	    fn name(&self) -> String {
61	        "anthropic".to_string()
62	    }
63	
64	    async fn discover_tools(&self) -> Result<Vec<ToolInvocation>, String> {
65	        Ok(Vec::new())
66	    }
67	
68	    async fn send(&self, request: ProviderRequest) -> ProviderResponse {
69	        let url = "https://api.anthropic.com/v1/messages";
70	        let model = request
71	            .model
72	            .as_ref()
73	            .cloned()
74	            .unwrap_or_else(|| "claude-3-5-sonnet-20241022".to_string());
75	
76	        let body = json!({
77	            "model": model,
78	            "max_tokens": request.max_tokens,
79	            "system": request.system.unwrap_or_default(),
80	            "messages": [{"role": "user", "content": request.prompt}]
81	        });
82	
83	        let resp = self
84	            .client
85	            .post(url)
86	            .header("x-api-key", &self.api_key)
87	            .header("anthropic-version", "2023-06-01")
88	            .json(&body)
89	            .send()
90	            .await;
91	
92	        match resp {
93	            Ok(r) => {
94	                let data: serde_json::Value = r.json().await.unwrap_or_else(|_| json!({}));
95	                ProviderResponse {
96	                    text: data["content"][0]["text"]
97	                        .as_str()
98	                        .unwrap_or("Error: No text in response")
99	                        .to_string(),
100	                    provider: self.name(),
101	                    model,
102	                    tokens: 0,
103	                    latency_ms: 0.0,
104	                    status: "success".to_string(),
105	                    error: None,
106	                }
107	            }
108	            Err(e) => ProviderResponse {
109	                text: "".to_string(),
110	                provider: self.name(),
111	                model: "".to_string(),
112	                tokens: 0,
113	                latency_ms: 0.0,
114	                status: "error".to_string(),
115	                error: Some(e.to_string()),
116	            },
117	        }
118	    }
119	}
120	
121	/// OpenAI Spoke: Implementation for GPT
122	pub struct OpenAiSpoke {
123	    /// API Key
124	    pub api_key: String,
125	    client: Client,
126	}
127	
128	impl OpenAiSpoke {
129	    /// Create new OpenAI spoke
130	    pub fn new(api_key: String) -> Self {
131	        Self {
132	            api_key,
133	            client: Client::new(),
