1	//! omega-dream: Dream-to-Waking feedback loop
2	//!
3	//! DREAM processes verification failures and learns from them,
4	//! converting "dreams" (failed attempts) into "waking" knowledge via feedback loops.
5	#![warn(missing_docs)]
6	
7	use omega_core::{now, VerificationReport};
8	use serde::{Deserialize, Serialize};
9	use std::collections::HashMap;
10	
11	/// A dream episode representing a failed verification
12	#[derive(Clone, Debug, Serialize, Deserialize)]
13	pub struct DreamEpisode {
14	    /// Unique episode ID
15	    pub episode_id: String,
16	    /// Original response that failed verification
17	    pub failed_response: String,
18	    /// Verification report showing what failed
19	    pub failure_report: String,
20	    /// Corrected/improved response
21	    pub corrected_response: Option<String>,
22	    /// Lessons learned from this failure
23	    pub lessons: Vec<String>,
24	    /// Timestamp of episode
25	    pub timestamp: f64,
26	}
27	
28	/// Dream-to-Waking feedback configuration
29	#[derive(Clone, Debug, Serialize, Deserialize)]
30	pub struct DreamConfig {
31	    /// Whether to record dream episodes
32	    pub recording_enabled: bool,
33	    /// Maximum number of dream episodes to store
34	    pub max_episodes: usize,
35	    /// Minimum confidence to apply learned lessons
36	    pub min_lesson_confidence: f64,
37	}
38	
39	impl Default for DreamConfig {
40	    fn default() -> Self {
41	        DreamConfig {
42	            recording_enabled: true,
43	            max_episodes: 1000,
44	            min_lesson_confidence: 0.7,
45	        }
46	    }
47	}
48	
49	/// Dream-to-Waking service
50	#[derive(Clone, Debug)]
51	pub struct Service {
52	    config: DreamConfig,
53	    episodes: Vec<DreamEpisode>,
54	    pattern_cache: HashMap<String, usize>,
55	}
56	
57	impl Service {
58	    /// Create a new DREAM service with default configuration
59	    pub fn new() -> Self {
60	        Self::with_config(DreamConfig::default())
61	    }
62	
63	    /// Create a new DREAM service with custom configuration
64	    pub fn with_config(config: DreamConfig) -> Self {
65	        Service {
66	            config,
67	            episodes: Vec::new(),
68	            pattern_cache: HashMap::new(),
69	        }
70	    }
71	
72	    /// Record a verification failure as a dream episode
73	    pub fn record_failure(&mut self, response: &str, report: &VerificationReport) -> DreamEpisode {
74	        if !self.config.recording_enabled {
75	            return DreamEpisode {
76	                episode_id: String::new(),
77	                failed_response: response.to_string(),
78	                failure_report: String::new(),
79	                corrected_response: None,
80	                lessons: Vec::new(),
81	                timestamp: now(),
82	            };
83	        }
84	
85	        let episode_id = format!("drm-{}", self.episodes.len() + 1);
86	        let failure_reasons = self.extract_failure_reasons(report);
87	
88	        let episode = DreamEpisode {
89	            episode_id: episode_id.clone(),
90	            failed_response: response.to_string(),
91	            failure_report: format!("{:?}", report.flags),
92	            corrected_response: None,
93	            lessons: self.derive_lessons(&failure_reasons),
94	            timestamp: now(),
95	        };
96	
97	        self.episodes.push(episode.clone());
98	
99	        // Update pattern cache
100	        for flag in &report.flags {
101	            *self.pattern_cache.entry(flag.clone()).or_insert(0) += 1;
102	        }
103	
104	        // Enforce max episodes limit
105	        if self.episodes.len() > self.config.max_episodes {
106	            self.episodes.remove(0);
107	        }
108	
109	        episode
110	    }
111	
112	    /// Extract failure reasons from verification report
113	    fn extract_failure_reasons(&self, report: &VerificationReport) -> Vec<String> {
114	        let mut reasons = Vec::new();
115	
116	        for flag in &report.flags {
117	            reasons.push(flag.clone());
118	        }
119	
120	        if report.score < 0.5 {
121	            reasons.push("low_verification_score".to_string());
122	        }
123	
124	        reasons
125	    }
126	
127	    /// Derive lessons from failure patterns
128	    fn derive_lessons(&self, failure_reasons: &[String]) -> Vec<String> {
129	        let mut lessons = Vec::new();
130	
131	        for reason in failure_reasons {
132	            let lesson = match reason.as_str() {
133	                "HALLUCINATION_RISK" => "Remove claims without supporting evidence",
134	                "INCOHERENCE_DETECTED" => "Ensure response maintains logical consistency",
135	                "EMPTY_RESPONSE" => "Always provide meaningful content",
136	                "RESPONSE_TOO_SHORT" => "Expand response with substantive details",
137	                "low_verification_score" => "Improve alignment with task objective",
138	                _ => "Review this failure case for patterns",
139	            };
140	
141	            lessons.push(lesson.to_string());
142	        }
143	
144	        lessons
145	    }
146	
147	    /// Get dream episodes matching a pattern
148	    pub fn retrieve_dreams(&self, pattern: &str) -> Vec<DreamEpisode> {
149	        self.episodes
150	            .iter()
151	            .filter(|e| e.lessons.iter().any(|l| l.contains(pattern)))
152	            .cloned()
153	            .collect()
154	    }
155	
156	    /// Get most common failure patterns
157	    pub fn get_failure_patterns(&self) -> Vec<(String, usize)> {
158	        let mut patterns: Vec<(String, usize)> = self
159	            .pattern_cache
160	            .iter()
161	            .map(|(k, v)| (k.clone(), *v))
162	            .collect();
163	        patterns.sort_by(|a, b| b.1.cmp(&a.1));
164	        patterns
165	    }
166	
167	    /// Get dream episode count
168	    pub fn episode_count(&self) -> usize {
169	        self.episodes.len()
170	    }
171	
172	    /// Get overall dream statistics
173	    pub fn get_statistics(&self) -> DreamStatistics {
174	        let total_episodes = self.episodes.len();
175	        let lessons_learned = self.episodes.iter().flat_map(|e| &e.lessons).count();
176	        let avg_lessons_per_episode = if total_episodes > 0 {
177	            lessons_learned as f64 / total_episodes as f64
178	        } else {
179	            0.0
180	        };
181	
182	        DreamStatistics {
183	            total_episodes,
184	            lessons_learned,
185	            avg_lessons_per_episode,
186	            most_common_failures: self.get_failure_patterns()
187	                [0..std::cmp::min(5, self.pattern_cache.len())]
188	                .to_vec(),
189	        }
190	    }
191	}
192	
193	/// Dream statistics
194	#[derive(Clone, Debug, Serialize, Deserialize)]
195	pub struct DreamStatistics {
196	    /// Total dream episodes recorded
197	    pub total_episodes: usize,
198	    /// Total lessons learned across all episodes
199	    pub lessons_learned: usize,
200	    /// Average lessons per episode
201	    pub avg_lessons_per_episode: f64,
202	    /// Top 5 most common failure patterns
203	    pub most_common_failures: Vec<(String, usize)>,
204	}
205	
206	impl Default for Service {
207	    fn default() -> Self {
208	        Self::new()
209	    }
210	}
211	
212	#[cfg(test)]
213	mod tests {
214	    use super::*;
215	
216	    #[test]
217	    fn test_dream_episode_recording() {
218	        let mut service = Service::new();
219	        let report = VerificationReport {
220	            report_id: "test".to_string(),
