1	//! omega-integration: gAIng coordination and integration
2	//!
3	//! Integration layer coordinates all subsystems into a unified cognitive system.
4	
5	#![warn(missing_docs)]
6	
7	pub mod tool_router;
8	
9	use omega_spokes::{SpokeCapability, SpokeRegistry};
10	use serde::{Deserialize, Serialize};
11	use std::collections::HashMap;
12	use std::sync::Arc;
13	use tokio::sync::RwLock;
14	
15	/// Integration coordinator
16	#[derive(Clone, Debug, Serialize, Deserialize)]
17	pub struct IntegrationMessage {
18	    /// Source system
19	    pub source: String,
20	    /// Destination system
21	    pub destination: String,
22	    /// Message type
23	    pub message_type: String,
24	    /// Message payload
25	    pub payload: serde_json::Value,
26	    /// Timestamp
27	    pub timestamp: f64,
28	}
29	
30	/// gAIng coordination service
31	#[derive(Clone)]
32	pub struct Service {
33	    message_queue: Vec<IntegrationMessage>,
34	    system_registry: HashMap<String, SystemStatus>,
35	    spoke_registry: Arc<RwLock<Option<Arc<SpokeRegistry>>>>,
36	}
37	
38	/// Status of an integrated system
39	#[derive(Clone, Debug, Serialize, Deserialize)]
40	pub struct SystemStatus {
41	    /// System name
42	    pub name: String,
43	    /// Is system healthy
44	    pub healthy: bool,
45	    /// Last heartbeat
46	    pub last_heartbeat: f64,
47	    /// Message count
48	    pub message_count: u64,
49	}
50	
51	impl Service {
52	    /// Create new integration service
53	    pub fn new() -> Self {
54	        Service {
55	            message_queue: Vec::new(),
56	            system_registry: HashMap::new(),
57	            spoke_registry: Arc::new(RwLock::new(None)),
58	        }
59	    }
60	
61	    /// Set the spoke registry for this integration service
62	    pub async fn set_spoke_registry(&self, registry: Arc<SpokeRegistry>) {
63	        let mut reg = self.spoke_registry.write().await;
64	        *reg = Some(registry);
65	    }
66	
67	    /// Find the provider spoke for a given tool
68	    pub async fn find_tool_provider(&self, tool_name: &str) -> Option<String> {
69	        let reg = self.spoke_registry.read().await;
70	        if let Some(registry) = reg.as_ref() {
71	            registry.find_tool_provider(tool_name).map(|s| s.name())
72	        } else {
73	            None
74	        }
75	    }
76	
77	    /// Get spokes that have a specific capability
78	    pub async fn spokes_with_capability(&self, capability: SpokeCapability) -> Vec<String> {
79	        let reg = self.spoke_registry.read().await;
80	        if let Some(registry) = reg.as_ref() {
81	            registry
82	                .spokes_with_capability(capability)
83	                .iter()
84	                .map(|s| s.name())
85	                .collect()
86	        } else {
87	            Vec::new()
88	        }
89	    }
90	
91	    /// Register a system
92	    pub fn register_system(&mut self, name: &str, timestamp: f64) {
93	        self.system_registry.insert(
94	            name.to_string(),
95	            SystemStatus {
96	                name: name.to_string(),
97	                healthy: true,
98	                last_heartbeat: timestamp,
99	                message_count: 0,
100	            },
101	        );
102	    }
103	
104	    /// Send message between systems
105	    pub fn send_message(
106	        &mut self,
107	        from: &str,
108	        to: &str,
109	        msg_type: &str,
110	        payload: serde_json::Value,
111	        timestamp: f64,
112	    ) {
113	        let msg = IntegrationMessage {
114	            source: from.to_string(),
115	            destination: to.to_string(),
116	            message_type: msg_type.to_string(),
117	            payload,
118	            timestamp,
119	        };
120	
121	        self.message_queue.push(msg);
122	
123	        // Update sender's message count
124	        if let Some(sys) = self.system_registry.get_mut(from) {
125	            sys.message_count += 1;
126	        }
127	    }
128	
129	    /// Get queued messages
130	    pub fn get_messages(&self) -> Vec<IntegrationMessage> {
131	        self.message_queue.clone()
132	    }
133	
134	    /// Clear message queue
135	    pub fn clear_queue(&mut self) {
136	        self.message_queue.clear();
137	    }
138	
139	    /// Update system heartbeat
140	    pub fn heartbeat(&mut self, system: &str, timestamp: f64) {
141	        if let Some(status) = self.system_registry.get_mut(system) {
142	            status.last_heartbeat = timestamp;
143	        }
144	    }
145	
146	    /// Get system status
147	    pub fn get_status(&self, system: &str) -> Option<SystemStatus> {
148	        self.system_registry.get(system).cloned()
149	    }
150	
151	    /// Check if all systems are healthy
152	    pub fn all_healthy(&self) -> bool {
153	        self.system_registry.values().all(|s| s.healthy)
154	    }
155	
156	    /// Coordinate systems
157	    pub fn coordinate(&self) -> CoordinationReport {
158	        let healthy_count = self.system_registry.values().filter(|s| s.healthy).count();
159	        let total_messages = self.system_registry.values().map(|s| s.message_count).sum();
160	
161	        CoordinationReport {
162	            system_count: self.system_registry.len(),
163	            healthy_count,
164	            total_messages,
165	            queue_size: self.message_queue.len(),
166	        }
167	    }
168	}
169	
170	/// Coordination report
