// omega-metacog: Reflective agent for autonomous insight generation.
// The metacog layer analyzes the MemoryGraph to identify patterns,
// drifts, and opportunities for cognitive optimization.

#![warn(missing_docs)]

pub mod dream;

use omega_core::now;
use omega_myelin::MemoryGraph;
use serde::{Deserialize, Serialize};

/// Epiphany: A synthetic policy update generated by the metacog agent.
#[derive(Clone, Debug, Serialize, Deserialize)]
pub struct Epiphany {
    /// Human-readable description of the insight
    pub insight: String,
    /// IDs of memory nodes that triggered this epiphany
    pub supporting_nodes: Vec<String>,
    /// Confidence score [0.0, 1.0]
    pub confidence: f64,
    /// Category of insight
    pub category: EpiphanyCategory,
    /// Unix timestamp
    pub timestamp: f64,
}

/// Categories of insight the metacog agent can generate
#[derive(Clone, Debug, Serialize, Deserialize, PartialEq, Eq)]
pub enum EpiphanyCategory {
    /// A concept is accessed frequently and should be promoted in retrieval priority
    HotNode,
    /// A concept's decay score has dropped below relevance threshold — prune candidate
    ColdNode,
    /// Threat pattern appears repeatedly — escalate to AEGIS
    ThreatEscalation,
    /// Multiple related nodes are accessed together — suggests a cluster that could be merged
    ClusterCandidate,
    /// A node has never been retrieved despite high connectivity — orphaned knowledge
    OrphanedKnowledge,
    /// Recent retrieval rate has spiked — possible topic shift in operator focus
    TopicShift,
}

/// MetacogAgent: Performs reflective analysis on the MemoryGraph.
pub struct MetacogAgent {
    /// Epiphanies generated across all reflection cycles
    pub history: Vec<Epiphany>,
    /// Minimum retrieval count to qualify as a HotNode
    hot_threshold: u32,
    /// Maximum decay score before a node is considered Cold
    cold_threshold: f64,
    /// Minimum decay score for a node to be considered active
    active_floor: f64,
}

impl MetacogAgent {
    /// Initialize a new agent with default thresholds
    pub fn new() -> Self {
        Self {
            history: Vec::new(),
            hot_threshold: 5,
            cold_threshold: 0.15,
            active_floor: 0.05,
        }
    }

    /// Perform a full reflection cycle on the given memory graph.
    ///
    /// Runs six analysis passes:
    /// 1. Hot node detection (high retrieval, low decay — stabilize)
    /// 2. Cold node detection (very low decay — prune candidates)
    /// 3. Threat pattern escalation (repeated threat nodes)
    /// 4. Cluster detection (nodes accessed together)
    /// 5. Orphaned knowledge (connected but never retrieved)
    /// 6. Topic shift detection (sudden retrieval spike)
    pub fn reflect(&mut self, graph: &MemoryGraph) -> Vec<Epiphany> {
        let mut new_insights: Vec<Epiphany> = Vec::new();

        // Pass 1: Hot nodes — high retrieval + low decay = priority stabilization target
        for (id, node) in &graph.nodes {
            if node.retrieval_count >= self.hot_threshold && node.decay_score < 0.3 {
                new_insights.push(Epiphany {
                    insight: format!(
                        "Hot cognitive focus on '{}' ({} retrievals, decay={:.2}). \
                        Promote retrieval priority and consider consolidating related nodes.",
                        &node.content[..node.content.len().min(60)],
                        node.retrieval_count,
                        node.decay_score,
                    ),
                    supporting_nodes: vec![id.clone()],
                    confidence: 0.85 + (node.retrieval_count as f64 * 0.01).min(0.14),
                    category: EpiphanyCategory::HotNode,
                    timestamp: now(),
                });
            }
        }

        // Pass 2: Cold nodes — decay below floor = prune candidates
        for (id, node) in &graph.nodes {
            if node.decay_score < self.cold_threshold && node.retrieval_count == 0 {
                new_insights.push(Epiphany {
                    insight: format!(
                        "Cold node '{}' has never been retrieved and has decayed to {:.3}. \
                        Candidate for pruning or archival.",
                        &node.content[..node.content.len().min(60)],
                        node.decay_score,
                    ),
                    supporting_nodes: vec![id.clone()],
                    confidence: 0.75,
                    category: EpiphanyCategory::ColdNode,
                    timestamp: now(),
                });
            }
        }

        // Pass 3: Threat escalation — nodes tagged as threats appearing repeatedly
        let threat_nodes: Vec<(&String, &omega_core::MemoryNode)> = graph.nodes.iter()
            .filter(|(_, n)| n.tags.iter().any(|t| t.contains("threat") || t.contains("attack")))
            .collect();
        if threat_nodes.len() >= 3 {
            let ids: Vec<String> = threat_nodes.iter().map(|(id, _)| (*id).clone()).collect();
            let top_tag = threat_nodes.iter()
                .flat_map(|(_, n)| n.tags.iter())
                .filter(|t| t.contains("threat"))
                .max_by_key(|t| t.len())
                .cloned()
                .unwrap_or_default();
            new_insights.push(Epiphany {
                insight: format!(
                    "{} threat-tagged nodes detected in memory (top pattern: '{}').\
                    Escalating to AEGIS for policy hardening.",
                    threat_nodes.len(), top_tag,
                ),
                supporting_nodes: ids,
                confidence: 0.92,
                category: EpiphanyCategory::ThreatEscalation,
                timestamp: now(),
            });
        }

        // Pass 4: Cluster detection — find groups of nodes with shared tags
        let mut tag_buckets: std::collections::HashMap<String, Vec<String>> =
            std::collections::HashMap::new();
        for (id, node) in &graph.nodes {
            for tag in &node.tags {
                tag_buckets.entry(tag.clone()).or_default().push(id.clone());
            }
        }
        for (tag, ids) in &tag_buckets {
            if ids.len() >= 4 {
                new_insights.push(Epiphany {
                    insight: format!(
                        "{} nodes share tag '{}' — cluster candidate. \
                        Consider consolidating into a single high-weight node.",
                        ids.len(), tag,
                    ),
                    supporting_nodes: ids.clone(),
                    confidence: 0.70,
                    category: EpiphanyCategory::ClusterCandidate,
                    timestamp: now(),
                });
            }
        }

        // Pass 5: Orphaned knowledge — nodes with edges but zero retrievals
        let connected_ids: std::collections::HashSet<String> = graph.edges.iter()
            .flat_map(|e| [e.from_id.clone(), e.to_id.clone()])
            .collect();
        for (id, node) in &graph.nodes {
            if connected_ids.contains(id) && node.retrieval_count == 0
                && node.decay_score > self.active_floor
            {
                new_insights.push(Epiphany {
                    insight: format!(
                        "Node '{}' is connected to {} other nodes but has never been retrieved. \
                        Potential orphaned knowledge — review for relevance.",
                        &node.content[..node.content.len().min(60)],
                        graph.edges.iter().filter(|e| &e.from_id == id || &e.to_id == id).count(),
                    ),
                    supporting_nodes: vec![id.clone()],
                    confidence: 0.65,
                    category: EpiphanyCategory::OrphanedKnowledge,
                    timestamp: now(),
                });
            }
        }

        // Pass 6: Topic shift — retrieval rate spike in recent history
        if graph.episodes.len() >= 2 {
            let recent = &graph.episodes[graph.episodes.len().saturating_sub(5)..];
            let older = &graph.episodes[..graph.episodes.len().saturating_sub(5)];
            if !older.is_empty() {
                let recent_avg = recent.iter().map(|e| e.nodes_accessed.len()).sum::<usize>() as f64
                    / recent.len() as f64;
                let older_avg = older.iter().map(|e| e.nodes_accessed.len()).sum::<usize>() as f64
                    / older.len() as f64;
                if recent_avg > older_avg * 2.0 && older_avg > 0.0 {
                    new_insights.push(Epiphany {
                        insight: format!(
                            "Retrieval rate spiked {:.1}x over baseline ({:.1} vs {:.1} nodes/episode). \
                            Possible topic shift in operator focus — consider pre-warming related nodes.",
                            recent_avg / older_avg, recent_avg, older_avg,
                        ),
                        supporting_nodes: vec![],
                        confidence: 0.78,
